#include <bits/stdc++.h>
using namespace std;
int t,n;
string s;
int main()
{
    // freopen("P12651_4.in","r",stdin);
    // freopen("myout.out","w",stdout);
    cin>>t;
    while(t--)
    {
        cin>>n>>s;
        int first_1=0x3f3f3f3f;
        for(int i=0;i<n;i++)
        {
            if(s[i]=='1')
            {
                first_1=i;
                break;
            }
        }
        if(first_1==0x3f3f3f3f)
        {
            cout<<"0\n";
            continue;
        }
        int flag=0x3f3f3f3f;
        for(int i=first_1+1;i<n;i++)
        {
            if(s[i]=='0')
            {
                flag=i;
                break;
            }
        }
        if(flag==0x3f3f3f3f)
        {
            for(int i=first_1;i<n-1;i++) cout<<1;
            if(first_1==0) cout<<0;
            else cout<<1;
            cout<<"\n";
            continue;
        }
        // cout<<flag<<"\n";
        for(int i=first_1;i<flag;i++) cout<<1;
        int lianxu_0cnt=0;
        for(int i=flag;i<n;i++)
        {
            if(s[i]=='1') break;
            lianxu_0cnt++;
        }
        for(int l=max(first_1,flag-lianxu_0cnt),r=flag;r<n;l++,r++)
        {
            cout<<"10"[s[l]==s[r]];
        }
        cout<<'\n';
    }
    return 0;
}
